import React, { useEffect } from "react";
import { MapContainer, TileLayer, Marker, useMap } from "react-leaflet";
import L from "leaflet";
import "leaflet-routing-machine";

function Routing({ origin, destination }) {

  const map = useMap();

  useEffect(() => {

    if (!origin || !destination) return;

    L.Routing.control({

      waypoints: [
        L.latLng(origin.lat, origin.lon),
        L.latLng(destination.lat, destination.lon)
      ],

      lineOptions: {
        styles: [{ color: "#ff4f81", weight: 6 }]
      },

      createMarker: function (i, point) {

        return L.marker(point.latLng);

      },

    }).addTo(map);

  }, [origin, destination, map]);

  return null;

}

function GoogleMapView({ originCoords, destinationCoords }) {

  if (!originCoords) return null;

  return (

    <MapContainer
      center={[originCoords.lat, originCoords.lon]}
      zoom={13}
      style={{ height: "400px", width: "100%", borderRadius: "15px" }}
    >

      {/* Pink map tiles */}

      <TileLayer
        url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
      />

      <Marker position={[originCoords.lat, originCoords.lon]} />

      {destinationCoords && (

        <Routing
          origin={originCoords}
          destination={destinationCoords}
        />

      )}

    </MapContainer>

  );

}

export default GoogleMapView;
